//
//
// Note: describe is only supported in Global scope.
// Use 'describe' to create a suite of test scripts and 'it' to define test expectations
//
//  Example jasmine test:
//
//      describe('my suite of script tests', function() {
//            it('should meet expectations', function() {
//                  expect(true).not.toBe(false);
//            });
//      });
//      // make sure to uncomment jasmine.getEnv().execute(); outside the function body
//
//
// assertEqual: A function used to compare that assertion.shouldbe == assertion.value;
//              in case of failure it throws an Error and logs that the assertion by
//              name has failed
//
//  Example:
//
//      var testAssertion = {
//            name: "my test assertion",
//            shouldbe: "expected value"
//            value: "actual value",
//      };
//      assertEqual(testAssertion); // throws Error, logs message to test step output
//
(function (outputs, steps, stepResult, assertEqual) {
	
	var propName = 'x_taniu_tan_core.tanium_module_api_url';
	var moduleEndpoint = gs.getProperty(propName, '');
	var beginString = 'https://';
	var endString = '/plugin/products';
	
	//Check for errors
	if (!moduleEndpoint) {
		stepResult.setOutputMessage(
			'System property "' + propName + '" has not been set. Please set this property to ' +
			'the API URL of your instance, including "' + beginString + '" at the beginning, and ' +
			'"' + endString + '" at the end. You can set this property by following the guided ' +
			'setup steps from Tanium Integration Core > Guided Setup in the Application ' +
			'Navigator bar of your ServiceNow instance.'
		);
		return false;
	}
	if (moduleEndpoint.indexOf(beginString) != 0) {
		stepResult.setOutputMessage(
			'System property "' + propName + '" does not begin with ' + beginString + '. ' +
			'Please update this property so that it contains a valid HTTPS URL that points ' +
			'to your Tanium instance, including "' + beginString + '" at the beginning, and ' +
			'"' + endString + '" at the end. You can set this property by following the guided ' +
			'setup steps from Tanium Integration Core > Guided Setup in the Application ' +
			'Navigator bar of your ServiceNow instance.'
		);
		return false;
	}
	if (moduleEndpoint.indexOf(endString) != (moduleEndpoint.length - endString.length)) {
		stepResult.setOutputMessage(
			'System property "' + propName + '" does not end with "' + endString + '". ' +
			'Please update this property so that it contains a valid HTTPS URL that points ' +
			'to your Tanium instance, including "' + beginString + '" at the beginning, and ' +
			'"' + endString + '" at the end. You can set this property by following the guided ' +
			'setup steps from Tanium Integration Core > Guided Setup in the Application ' +
			'Navigator bar of your ServiceNow instance.'
		);
		return false;
	}
	
	//If no errors caused a bail, return true.
	stepResult.setOutputMessage(
		'Successfully validated the ' + propName + ' system property.'
	);
	return true;
	
})(outputs, steps, stepResult, assertEqual);
// uncomment the next line to execute this script as a jasmine test
